class Solution {
    public char kthCharacter(long k, int[] operations) {
        long len = 1;
        int shift = 0;
        for (int op : operations) {
            if (len >= k) break;
            if (op == 0) {
                len <<= 1;
            } else {
                if (k > len) {
                    k -= len;
                    shift++;
                }
                len <<= 1;
            }
        }
        return (char) ('a' + (shift % 26));
    }
}
```
